public class MultiInterface {
    interface A { default String hello() { return "A"; } }
    interface B extends A { default String hello() { return "B"; } }
    static class C implements A, B {
        // B.hello() overrides A.hello() — no conflict
    }
    static class D implements A, B {
        public String hello() { return "D"; }  // explicit override
    }
    public static void main(String[] args) {
        System.out.println(new C().hello());
        System.out.println(new D().hello());
        System.out.println(new C() instanceof A);
        System.out.println(new C() instanceof B);
    }
}
